import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const STEPS = [
  'Care Type',
  'Patient Details',
  'Requirements',
  'Schedule',
  'Location',
  'Select Caregiver',
  'Review'
];

const initialForm = {
  careType: '',
  patient: { name: '', age: '', gender: '', medicalConditions: '' },
  careRequirements: [],
  schedule: { startDate: '', endDate: '', timeSlot: '', duration: '' },
  location: { address: '', city: '', pincode: '' },
  additionalNotes: ''
};

export default function BookingForm() {
  const [step, setStep] = useState(0);
  const [form, setForm] = useState(initialForm);
  const [caregivers, setCaregivers] = useState([]);
  const [caregiverId, setCaregiverId] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    axios.get('http://localhost:5000/api/caregivers')
      .then(res => setCaregivers(res.data))
      .catch(err => console.log(err));
  }, []);

  const setPatient = (f, v) => setForm(prev => ({ ...prev, patient: { ...prev.patient, [f]: v } }));
  const setSchedule = (f, v) => setForm(prev => ({ ...prev, schedule: { ...prev.schedule, [f]: v } }));
  const setLocation = (f, v) => setForm(prev => ({ ...prev, location: { ...prev.location, [f]: v } }));

  const canNext = () => {
    if (step === 0) return form.careType;
    if (step === 1) return form.patient.name && form.patient.age && form.patient.gender;
    if (step === 2) return form.careRequirements.length > 0;
    if (step === 3) return form.schedule.startDate && form.schedule.duration;
    if (step === 4) return form.location.address;
    if (step === 5) return caregiverId;
    return true;
  };

  const handleSubmit = async () => {
    try {
      await axios.post(
        'http://localhost:5000/api/bookings',
        {
          ...form,
          caregiverId
        },
        {
          headers: {
            Authorization: `Bearer ${localStorage.getItem("token")}`
          }
        }
      );

      alert("Booking Successful!");
      navigate('/dashboard');

    } catch (err) {
      console.log(err.response?.data || err.message);
      alert("Booking failed. Check console.");
    }
  };

  return (
    <div className="main-content">

      <div className="page-header">
        <h1 className="page-title">Book a Caregiver</h1>
        <p className="page-sub">Step {step + 1} of {STEPS.length}</p>
      </div>

      <div className="card p-6">

        <h2 className="section-title">{STEPS[step]}</h2>

        {/* STEP 0 */}
        {step === 0 && (
          <select className="form-select"
            onChange={(e) => setForm({ ...form, careType: e.target.value })}
          >
            <option value="">Select Care Type</option>
            <option value="elderly">Elderly</option>
            <option value="maternity">Pregnant Woman</option>
            <option value="childcare">Child</option>
          </select>
        )}

        {/* STEP 1 */}
        {step === 1 && (
          <>
            <input className="form-input"
              placeholder="Patient Name"
              onChange={e => setPatient('name', e.target.value)}
            />

            <input className="form-input"
              type="number"
              placeholder="Age"
              onChange={e => setPatient('age', e.target.value)}
            />

            <select className="form-select"
              onChange={e => setPatient('gender', e.target.value)}
            >
              <option value="">Select Gender</option>
              <option value="male">Male</option>
              <option value="female">Female</option>
              <option value="other">Other</option>
            </select>
          </>
        )}

        {/* STEP 2 */}
        {step === 2 && (
          <button className="btn btn-outline w-full"
            onClick={() =>
              setForm(prev => ({
                ...prev,
                careRequirements: ['daily_assistance']
              }))
            }
          >
            Add Requirement
          </button>
        )}

        {/* STEP 3 */}
        {step === 3 && (
          <>
            <input className="form-input"
              type="date"
              onChange={e => setSchedule('startDate', e.target.value)}
            />

            <select className="form-select"
              onChange={e => setSchedule('duration', e.target.value)}
            >
              <option value="">Select Duration</option>
              <option value="4 hours">4 hours</option>
              <option value="8 hours">8 hours</option>
              <option value="Full Day">Full Day</option>
            </select>
          </>
        )}

        {/* STEP 4 */}
        {step === 4 && (
          <input className="form-input"
            placeholder="Address"
            onChange={e => setLocation('address', e.target.value)}
          />
        )}

        {/* STEP 5 */}
        {step === 5 && (
          <select className="form-select"
            value={caregiverId}
            onChange={(e) => setCaregiverId(e.target.value)}
          >
            <option value="">Select Caregiver</option>
            {caregivers.map(cg => (
              <option key={cg._id} value={cg._id}>
                {cg.user?.name} - {cg.specializations?.join(', ')}
              </option>
            ))}
          </select>
        )}

        {/* STEP 6 */}
        {step === 6 && (
          <div className="text-sm">
            <p><b>Care Type:</b> {form.careType}</p>
            <p><b>Patient:</b> {form.patient.name}</p>
            <p><b>Caregiver:</b> {caregiverId}</p>
          </div>
        )}

        {/* NAVIGATION */}
        <div className="flex justify-between mt-4">

          {step > 0 && (
            <button className="btn btn-ghost"
              onClick={() => setStep(step - 1)}
            >
              Back
            </button>
          )}

          {step < STEPS.length - 1 ? (
            <button className="btn btn-primary"
              onClick={() => setStep(step + 1)}
              disabled={!canNext()}
            >
              Next
            </button>
          ) : (
            <button className="btn btn-primary"
              onClick={handleSubmit}
            >
              Submit
            </button>
          )}

        </div>

      </div>
    </div>
  );
}
